const LOGO_B64 = "";

const TODAY = new Date("2026-03-02");

function getDays(fin) {
  if (!fin) return null;
  const d = new Date(fin);
  return Math.ceil((d - TODAY) / 86400000);
}

function computeStatus(fin, bloqueado) {
  if (bloqueado) return "BLOQUEADO";
  if (!fin) return "SIN PÓLIZA";
  const d = getDays(fin);
  if (d < 0) return "VENCIDA";
  if (d <= 10) return "CRÍTICO";
  if (d <= 15) return "ALERTA";
  return "VIGENTE";
}

